mapper.delete:
delete from default_approval_line 
	where drafter_rank_seq = #{rank_seq}
	or approver_rank_seq = #{rank_seq}

mapper.update:
        merge into rank target
        	using (
				select rank_seq, 
        			row_number() over (
						order by rank_order, rank_seq
					) as new_order
				from rank
			) source
			on (
				target.rank_seq = source.rank_seq
			)
		when matched then
			update set target.rank_order = source.new_order
